('PT', 'specjalistyczne'::question_type, 3, 'W jakim przypadku zalecane jest stosowanie piasecznic stanowiących wyposażenie tramwaju?', '{"A": "Tylko na nawierzchni pokrytej wodą.", "B": "Tylko na nawierzchni pokrytej śniegiem.", "C": "Na śliskiej szynie."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B205.jpg'),
('PT', 'specjalistyczne'::question_type, 3, 'Jakie czynniki mogą ograniczać pole widzenia motorniczego?', '{"A": "Osoby znajdujące się w kabinie.", "B": "Jedynie niekorzystne warunki atmosferyczne.", "C": "Reklamy umieszczone na bokach tramwaju."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B350.jpg'),
('PT', 'specjalistyczne'::question_type, 3, 'Który z wymienionych czynników może mieć wpływ na zmniejszenie pola widzenia motorniczego?', '{"A": "Jedynie intensywne opady atmosferyczne.", "B": "Osoba znajdująca się w kabinie.", "C": "Ergonomia fotela."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B351.jpg'),
('PT', 'specjalistyczne'::question_type, 3, 'Czy wzrost prędkości może mieć wpływ na sposób postrzegania przez motorniczego?', '{"A": "Tak, większa prędkość powoduje zmianę postrzegania.", "B": "Nie, postrzeganie przy dużej prędkości nie różni się od postrzegania przy mniejszych prędkościach.", "C": "Tak, ale tylko w przypadku jazdy w warunkach ograniczonej widoczności."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B352.jpg'),
('PT', 'specjalistyczne'::question_type, 3, 'Jaki czynnik może zakłócić prawidłowy sposób obserwacji drogi w czasie prowadzenia tramwaju w nocy?', '{"A": "Brak zdolności rozróżniania kształtów w mroku.", "B": "Używanie właściwie dobranych okularów do jazdy nocnej.", "C": "Właściwa ostrość wzroku kierującego."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B353.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'Czy możesz przejeżdżać pod izolatorem sekcyjnym z wciśniętym pedałem jazdy (przyspieszenia)?', '{"A": "Tak, ale z ograniczoną prędkością.", "B": "Nie, ponieważ może to spowodować uszkodzenie sieci trakcyjnej i pantografu.", "C": "Tak, z zachowaniem szczególnej ostrożności."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B401.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'Podczas przejazdu przez jaką zwrotnicę ma miejsce jazda na/pod iglicę?', '{"A": "Tylko sprężynową.", "B": "Prawoskrętną najazdową.", "C": "Lewoskrętną zjazdową."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B402.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'Co należy uwzględnić podczas przejazdu przez krzyżownicę tramwajową?', '{"A": "Liczbę pasażerów w tramwaju.", "B": "Płytkie rowki.", "C": "Prędkość tramwaju poprzedzającego i następnego."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B403.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'Jakie ustawienie nawrotnika może być przyczyną braku możliwości jazdy tramwajem dwu-wagonowym?', '{"A": "W pierwszym wagonie na \"P\" a w drugim wagonie na \"0\".", "B": "W pierwszym wagonie na \"P\" a w drugim wagonie na \"P\".", "C": "W pierwszym wagonie na \"T\" a w drugim wagonie na \"0\"."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B407.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'Jakie ustawienie nawrotnika może być przyczyną braku możliwości jazdy tramwajem jedno-wagonowym?', '{"A": "Nawrotnik ustawiony na \"0\".", "B": "Nawrotnik ustawiony na \"P\".", "C": "Nawrotnik ustawiony na \"T\"."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B408.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'Jakie ustawienie nawrotnika może być przyczyną braku możliwości jazdy tramwajem dwu-wagonowym?', '{"A": "W pierwszym wagonie na \"P\" a w drugim wagonie na \"0\".", "B": "W pierwszym wagonie na \"P\" a w drugim wagonie na \"T\".", "C": "W pierwszym wagonie na \"T\" a w drugim wagonie na \"0\"."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B409.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'Co należy zrobić w przypadku pojawienia się nadmiernego poślizgu kół (buksowania) podczas rozruchu?', '{"A": "Zatrzymać skład i następnie rozpocząć ruszanie.", "B": "Zmniejszyć intensywność rozpędzania tramwaju.", "C": "Zwiększyć intensywność rozpędzania tramwaju."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B410.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'Jak powinieneś ustawić zwrotnicę najazdową sterowaną hydraulicznie w przypadku konieczności przejazdu podczas cofania składem dwu-wagonowym?', '{"A": "Ustawić ją w pożądanym kierunku jazdy.", "B": "Ustawić ją dowolnie.", "C": "Nie nastawiać jej, ponieważ ustawi się samoczynnie pod ciężarem przejeżdżającego tramwaju."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B411.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'Jak powinieneś ustawić zwrotnicę zjazdową w przypadku konieczności przejazdu podczas cofania tramwajem?', '{"A": "Ustawić ją w przeciwnym kierunku jazdy.", "B": "Ustawić ją dowolnie.", "C": "Nie nastawiać jej, ponieważ ustawi się samoczynnie pod ciężarem przejeżdżającego tramwaju."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B412.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'Co służy do zmiany położenia iglicy w zwrotnicy sterowanej mechanicznie?', '{"A": "Nawrotnik.", "B": "Nastawiacz.", "C": "Nastawnik."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B416.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'Co służy do zmiany prędkości jazdy?', '{"A": "Nawrotnik.", "B": "Nastawnik.", "C": "Nastawiacz."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B417.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'Co umożliwia jazdę tramwajem do tyłu?', '{"A": "Nawrotnik.", "B": "Przestawiacz.", "C": "Nastawiacz."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8B418.jpg'),
('PT', 'specjalistyczne'::question_type, 3, 'Czy możesz kontynuować jazdę z pasażerami, po stwierdzeniu awarii mechanizmu zamykania drugich drzwi, w pierwszym wagonie?', '{"A": "Nie.", "B": "Tak, po zablokowaniu uszkodzonych drzwi i wyłączeniu \"blokady jazdy\".", "C": "Tak, z otwartymi drzwiami, ale tylko do najbliższej pętli tramwajowej."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C101.jpg'),
('PT', 'specjalistyczne'::question_type, 3, 'Których z podanych rodzajów hamulców, nie można sprawdzić na terenie zajezdni?', '{"A": "Bębnowych (szczękowych).", "B": "Elektrodynamicznych.", "C": "Szynowych."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C102.jpg'),
('PT', 'specjalistyczne'::question_type, 3, 'Którego, z podanych rodzajów hamulców, nie ma możliwości sprawdzić na terenie zajezdni?', '{"A": "Hamulca bezpieczeństwa.", "B": "Szynowego.", "C": "Elektrodynamicznego."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C103.jpg'),
('PT', 'specjalistyczne'::question_type, 3, 'Co, między innymi, należy sprawdzić przed przystąpieniem do jazdy tramwajem dwuwagonowym?', '{"A": "Wyposażenie apteczki.", "B": "Stan sprzęgu pomiędzy wagonami.", "C": "Wyposażenie wagonu w ostrzegawczy trójkąt odblaskowy."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C104.jpg'),
('PT', 'specjalistyczne'::question_type, 3, 'Co, między innymi, należy sprawdzić przed przystąpieniem do jazdy tramwajem?', '{"A": "Stan nadwozia i zamocowanie foteli pasażerskich, poręczy.", "B": "Termin ważności dowodu rejestracyjnego tramwaju.", "C": "Wyposażenie wagonu w ostrzegawczy trójkąt odblaskowy."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C105.jpg'),
('PT', 'specjalistyczne'::question_type, 3, 'W jakiej pozycji powinien znajdować się sprzęg podczas łączenia wagonów tramwajowych?', '{"A": "Złożony.", "B": "Rozłożony.", "C": "Pozycja sprzęgu nie ma znaczenia."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C106.jpg'),
('PT', 'specjalistyczne'::question_type, 3, 'Czego nie należy robić w trakcie sprzęgania ze sobą dwóch wagonów?', '{"A": "Luzować hamulców szczękowych wagonu sprzęganego.", "B": "Włączać świateł pozycyjnych.", "C": "Otwierać drzwi w drugim wagonie."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C107.jpg'),
('PT', 'specjalistyczne'::question_type, 3, 'Czego nie należy robić w trakcie sprzęgania ze sobą dwóch wagonów?', '{"A": "Zwalniać luzowników wagonu sprzęganego.", "B": "Włączać świateł obrysowych bocznych.", "C": "Stosować się do zasad BHP."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C108.jpg'),
('PT', 'specjalistyczne'::question_type, 3, 'Czym może być spowodowane rozłączenie stycznika liniowego w tramwaju?', '{"A": "Uszkodzoną przetwornicą.", "B": "Uszkodzonym nawrotnikiem.", "C": "Zwarciem w obwodach jednego z silników."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C109.jpg'),
('PT', 'specjalistyczne'::question_type, 1, 'Jaki dokument uprawnia do kierowania tramwajem?', '{"A": "Prawo jazdy kategorii B.", "B": "Prawo jazdy kategorii C.", "C": "Pozwolenie do kierowania tramwajem."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C250.jpg'),
('PT', 'specjalistyczne'::question_type, 1, 'Co mogą spowodować niskie obrzeża kół biegowych?', '{"A": "Wypadanie kół z torowiska.", "B": "Poślizg kół biegowych.", "C": "Zablokowanie zestawu kołowego."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C301.jpg'),
('PT', 'specjalistyczne'::question_type, 1, 'Co może spowodować wyszczerbiona wkładka grafitowa pantografu?', '{"A": "Znaczne zwiększenie oporów toczenia tramwaju.", "B": "Kołysanie sieci trakcyjnej.", "C": "Brak działania akumulatorów zasilających."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C302.jpg'),
('PT', 'specjalistyczne'::question_type, 1, 'Czym może być spowodowane samoczynne załączenie się hamulców szynowych?', '{"A": "Uszkodzeniem wału napędowego w tylnym zestawie kołowym.", "B": "Uszkodzeniem przetwornicy prądu.", "C": "Zaciągnięciem dźwigni hamulca bezpieczeństwa przez pasażera."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C303.jpg'),
('PT', 'specjalistyczne'::question_type, 1, 'Co należy zrobić w przypadku braku zadziałania zwrotnicy zdalnie sterowanej?', '{"A": "Przełożyć zwrotnicę ręcznie.", "B": "Cofnąć wagon za punkt nastawczy i ponownie przejechać.", "C": "Jechać według ustawionego kierunku zakładając, iż zwrotnica jest zablokowana."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C304.jpg'),
('PT', 'specjalistyczne'::question_type, 1, 'Jaka powinna być odległość dolnej krawędzi odgarniacza od główki szyny?', '{"A": "150 mm.", "B": "120 mm.", "C": "100 mm."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C306.jpg'),
('PT', 'specjalistyczne'::question_type, 1, 'Co może być przyczyną wydobywania się dymu z wózka napędowego?', '{"A": "Złe ustawienie nawrotnika w drugim wagonie.", "B": "Zwarcie w uzwojeniach silnika.", "C": "Nadmierny poślizg kół przy rozpędzaniu."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C307.jpg'),
('PT', 'specjalistyczne'::question_type, 1, 'Czy w przypadku stwierdzenia przepalenia jednej linki bocznikującej w pantografie dalsza jazda może być kontynuowana?', '{"A": "Tak, bez ograniczeń.", "B": "Nie, ponieważ dalsza jazda może doprowadzić do zwarcia linki z nadwoziem tramwaju.", "C": "Nie, ponieważ może spowodować przepalenie się drugiej linki pantografu."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C308.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'W jaki sposób należy wykonać nagłe hamowanie tramwajem?', '{"A": "W pierwszej fazie hamowania należy wcisnąć pedał hamulca do ogranicznika a następnie puścić pedał czuwaka.", "B": "Wcisnąć pedał hamulca poza ogranicznik bez zwalniania czuwaka.", "C": "Wcisnąć pedał hamulca poza ogranicznik i zwolnić dźwignię czuwaka."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C310.jpg'),
('PT', 'specjalistyczne'::question_type, 1, 'Co może spowodować uszkodzona przetwornica wirująca?', '{"A": "Brak możliwości przestawienia nastawiacza.", "B": "Brak możliwości przestawienia nawrotnika.", "C": "Brak chłodzenia aparatury elektrycznej."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C311.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'W jakiej sytuacji zaleca się stosowanie piasecznic znajdujących się na wyposażeniu tramwaju?', '{"A": "Zawsze przy hamowaniu.", "B": "Tylko na nawierzchni pokrytej wodą.", "C": "Przy nagłym hamowaniu awaryjnym."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C312.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'Co powinieneś zrobić kierując tramwajem wyposażonym w piasecznice w przypadku braku piasku w zbiornikach?', '{"A": "Zatrzymać tramwaj i czekać na obsługę techniczną.", "B": "Napełnić piasecznice żwirem.", "C": "Uzupełnić piasecznice specjalnym piaskiem na najbliższym krańcu."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8C313.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'O czym należy pamiętać przed rozpoczęciem holowania  składu tramwajów, uszkodzonego w wyniku kolizji?', '{"A": "O umieszczeniu trójkąta ostrzegawczego z tyłu drugiego wagonu.", "B": "O umieszczeniu żółtego sygnału błyskowego.", "C": "O połączeniu w sposób wykluczający odczepienie się w czasie jazdy."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8D101.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'O czym należy pamiętać przed rozpoczęciem spychania składu tramwajów, uszkodzonego w wyniku kolizji ?', '{"A": "O włączeniu świateł awaryjnych w pierwszym składzie.", "B": "O zwolnieniu luzowników w uszkodzonym wagonie.", "C": "O usadowieniu pasażerów na miejscach siedzących."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8D102.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'O czym należy pamiętać podczas spychania uszkodzonego w wyniku kolizji składu tramwajów?', '{"A": "O wydłużeniu drogi hamowania.", "B": "O umieszczeniu ostrzegawczego trójkąta odblaskowego z tyłu drugiego wagonu.", "C": "O usadowieniu pasażerów na miejscach siedzących."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8D103.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'Co powinieneś zrobić w przypadku agresywnego zachowania pasażera wobec Ciebie lub innych pasażerów, gdy sytuacja utrudnia kierowanie pojazdem?', '{"A": "Kontynuować jazdę do najbliższego komisariatu policji.", "B": "Zatrzymać pojazd i wezwać odpowiednie służby.", "C": "Nie podejmować żadnych działań."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8D150.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'O co należy zadbać, w pierwszej kolejności, w przypadku pożaru tramwaju podczas jazdy?', '{"A": "O bezpieczeństwo pasażerów i własne.", "B": "O zminimalizowanie uszkodzeń pojazdu.", "C": "O jazdę zgodną z rozkładem jazdy."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8D151.jpg'),
('PT', 'specjalistyczne'::question_type, 2, 'W jaki sposób zorganizować ewakuację pasażerów, jeżeli w wyniku wypadku drogowego nastąpiła blokada drzwi?', '{"A": "Wezwać pomoc drogową.", "B": "Skorzystać z wyjść awaryjnych.", "C": "Wezwać Straż Pożarną."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/8D152.jpg'),
