('T', 'specjalistyczne'::question_type, 3, 'Czego możesz się spodziewać, podczas gwałtownego hamowania, w takich warunkach drogowych?', '{"A": "Zwiększonej przyczepności kół do jezdni.", "B": "Zwiększonej siły tarcia.", "C": "Zmniejszonej przyczepności kół do jezdni."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/4B174.jpg'),
