('T', 'specjalistyczne'::question_type, 3, 'Czy na drodze publicznej dozwolone jest przewożenie w przyczepie ciągniętej przez ciągnik rolniczy ładunku przekraczającego jej dopuszczalną ładowność?', '{"A": "Tak, o ile dopuszczalna ładowność przyczepy nie jest przekroczona o więcej niż 40% wielkości nominalnej.", "B": "Nie.", "C": "Tak, ale tylko na trasie nieprzekraczającej 5 km."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/4C1B21_.jpg'),
('T', 'specjalistyczne'::question_type, 3, 'W jakich okolicznościach ładunek wystający z tyłu przyczepy ciągniętej przez ciągnik rolniczy powinien być oznakowany?', '{"A": "Jeżeli wystaje ponad 0,5 metra poza tylną płaszczyznę obrysu pojazdu.", "B": "Zawsze.", "C": "Wyłącznie podczas jazdy po drodze twardej."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/4C1B29_.jpg'),
('T', 'specjalistyczne'::question_type, 1, 'Który z tych obowiązków dotyczy właściciela ciągnika rolniczego?', '{"A": "Ubezpieczenie pojazdu w zakresie NW.", "B": "Zawiadomienie starosty w ciągu 30 dni o sprzedaży pojazdu.", "C": "Dokonywanie napraw ciągnika tylko w autoryzowanym serwisie."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/4C208_.jpg'),
('T', 'specjalistyczne'::question_type, 3, 'Który z wymienionych czynników w największym stopniu decyduje o długości drogi zatrzymania ciągnika rolniczego podczas awaryjnego hamowania?', '{"A": "Rodzaj i stan nawierzchni oraz warunki atmosferyczne.", "B": "Masa kierujacego ciagnikiem.", "C": "Dopuszczalna masa całkowita ciągnika."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/4B101_.jpg'),
('T', 'specjalistyczne'::question_type, 3, 'Od którego z wymienionych czynników, zależy przyczepność opon ciągnika rolniczego do nawierzchni jezdni?', '{"A": "Od masy przewożonego pasażera.", "B": "Od mocy silnika.", "C": "Od rodzaju i stanu nawierzchni jezdni."}'::jsonb, 'C', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/4B104_.jpg'),
('T', 'specjalistyczne'::question_type, 3, 'Który z wymienionych czynników, wpływa na wydłużenie drogi hamowania ciągnika rolniczego?', '{"A": "Zmniejszenie przyczepności opon do jezdni.", "B": "Zwiększenie przyczepności opon do jezdni.", "C": "Jazda pod górę."}'::jsonb, 'A', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/4B105_.jpg'),
('T', 'specjalistyczne'::question_type, 3, 'Jaki wpływ na długość drogi hamowania, ma zawilgocenie jezdni spowodowane deszczem?', '{"A": "Skraca drogę hamowania.", "B": "Wydłuża drogę hamowania.", "C": "Droga hamowania jest niezależna od stanu jezdni."}'::jsonb, 'B', 'https://qlpqmkqbimdwokeofyqq.supabase.co/storage/v1/object/public/question-media/4B107_.jpg'),
